(function(){if(typeof window.hjAG=="undefined")return;function s(t){const r=t.dataset.config||"{}";try{return JSON.parse(r)}catch(e){return{}}}function c(t,r){t.forEach(e=>{const n=e===r;e.classList.toggle("is-active",n),e.setAttribute("aria-pressed",n?"true":"false")})}async function d(t,r){const e=new URLSearchParams({action:"hj_ag_filter",nonce:window.hjAG.nonce,term:r||"0",config:JSON.stringify(t||{})});return(await fetch(window.hjAG.ajaxUrl,{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:e})).json()}function l(t){const r=Array.from(t.querySelectorAll(".hj-ag-filter"));if(!r.length)return;const e=t.querySelector(".hj-ag-grid");if(!e)return;const n=s(t);r.forEach(a=>{a.addEventListener("click",async()=>{if(!e.classList.contains("is-loading")){c(r,a),e.classList.add("is-loading");try{const o=a.dataset.term||"0",i=await d(n,o);i&&i.success&&i.data&&typeof i.data.html!="undefined"&&(e.innerHTML=i.data.html)}catch(o){console.error("Articles Grid filter error",o)}finally{e.classList.remove("is-loading")}}})})}document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".hj-articles-grid").forEach(l)})})();
